import React from 'react';
import { BrowserRouter as Router, Routes, Route, useLocation } from 'react-router-dom';
import { AnimatePresence } from 'framer-motion';
import Navbar from './components/Navbar';
import GlowMesh from './components/GlowMesh';
import PerspectiveContainer from './components/PerspectiveContainer';
import FloatingNodesBackground from './components/FloatingNodesBackground';
import PageTransition from './components/PageTransition';
import Home from './pages/Home';
import MapView from './pages/MapView';
import Login from './pages/Login';
import Register from './pages/Register';
import ForgotPassword from './pages/ForgotPassword';
import Profile from './pages/Profile';
import Itinerary from './pages/Itinerary'; 
import Safari from './pages/Safari';

const AppContent: React.FC = () => {
  const location = useLocation();

  return (
    <>
      {/* OPTICAL FILTER 3: Glow Mesh - Searchlight Effect */}
      <GlowMesh />

      {/* Z-AXIS DEPTH: Floating Node Environment - Parallax Background */}
      <FloatingNodesBackground />

      <PerspectiveContainer className="min-h-screen">
        <div className="min-h-screen bg-[#020202] selection:bg-[#00FF41]/30 text-white relative">
          <Navbar />
          <main>
            <AnimatePresence mode="wait">
              <Routes location={location} key={location.pathname}>
                <Route
                  path="/"
                  element={
                    <PageTransition>
                      <Home />
                    </PageTransition>
                  }
                />
                <Route
                  path="/login"
                  element={
                    <PageTransition>
                      <Login />
                    </PageTransition>
                  }
                />
                <Route
                  path="/register"
                  element={
                    <PageTransition>
                      <Register />
                    </PageTransition>
                  }
                />
                <Route
                  path="/forgot-password"
                  element={
                    <PageTransition>
                      <ForgotPassword />
                    </PageTransition>
                  }
                />
                <Route
                  path="/map"
                  element={
                    <PageTransition>
                      <MapView />
                    </PageTransition>
                  }
                />
                <Route
                  path="/itinerary"
                  element={
                    <PageTransition>
                      <Itinerary />
                    </PageTransition>
                  }
                />
                <Route
                  path="/profile"
                  element={
                    <PageTransition>
                      <Profile />
                    </PageTransition>
                  }
                />
              </Routes>
            </AnimatePresence>
          </main>
        </div>
      </PerspectiveContainer>

      {/* OPTICAL FILTER 1: Scan Lines Overlay - CRT Monitor Effect */}
      <div className="scan-lines" />
    </>
  );
};

const App: React.FC = () => {
  return (
    <Router>
      <AppContent />
    </Router>
  );
};

export default App;
